/**
 * @summary List all drops
 */
export const getListDropsUrl = (params?: ListDropsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/drops?${stringifiedParams}`
    : `/api/drops`;
};

export const listDrops = async (
  params?: ListDropsParams,
  options?: RequestInit,
): Promise<DropListResponse> => {
  return customFetch<DropListResponse>(getListDropsUrl(params), {
    ...options,
    method: "GET",
  });
};

